$ErrorActionPreference = "Stop"

$ProjectRoot = (Get-Location).Path
if (!(Test-Path ".\gradlew.bat")) {
    throw "Run this from the root of droingos-action-camera."
}

$Timestamp = Get-Date -Format "yyyyMMdd_HHmmss"
$BackupRoot = Join-Path $ProjectRoot "_camera_groups_backup_$Timestamp"
New-Item -ItemType Directory -Force -Path $BackupRoot | Out-Null

function Write-Base64File {
    param(
        [Parameter(Mandatory = $true)][string]$RelativePath,
        [Parameter(Mandatory = $true)][string]$Base64
    )

    $Destination = Join-Path $ProjectRoot ("src\main\java\net\droingo\actioncamera\" + $RelativePath)
    $Backup = Join-Path $BackupRoot $RelativePath

    New-Item -ItemType Directory -Force -Path (Split-Path $Backup -Parent) | Out-Null
    New-Item -ItemType Directory -Force -Path (Split-Path $Destination -Parent) | Out-Null

    if (Test-Path $Destination) {
        Copy-Item $Destination $Backup -Force
    }

    [System.IO.File]::WriteAllBytes(
        $Destination,
        [System.Convert]::FromBase64String($Base64)
    )

    Write-Host "Installed: $RelativePath"
}


$Data = "" +`n        "" +`n        "" +`n        "" +`n        "" +`n        ""
Write-Base64File -RelativePath "world\blockentity\ActionCameraBlockEntity.java" -Base64 $Data


