Write-Host ""
Write-Host "Camera groups, colours and side cycling installed." -ForegroundColor Green
Write-Host "Backup: $BackupRoot" -ForegroundColor Cyan
Write-Host ""
Write-Host "Compiling..." -ForegroundColor Cyan

& .\gradlew.bat compileJava

if ($LASTEXITCODE -ne 0) {
    Write-Host ""
    Write-Host "Compilation failed. Restoring backup..." -ForegroundColor Red

    Get-ChildItem -Path $BackupRoot -Recurse -File | ForEach-Object {
        $Relative = $_.FullName.Substring($BackupRoot.Length).TrimStart("\")
        $Destination = Join-Path $ProjectRoot ("src\main\java\net\droingo\actioncamera\" + $Relative)
        Copy-Item $_.FullName $Destination -Force
    }

    throw "Compilation failed and original files were restored."
}

